css:
body {
  font-family: Arial, sans-serif;
  font-size: 13px;
  color: #1a1a1a;
}

.stmt-header {
  text-align: center;
  border-bottom: 3px solid #2c5f2e;
  padding-bottom: 12px;
  margin-bottom: 20px;
}

.stmt-header h1 {
  margin: 0;
  font-size: 22px;
  color: #2c5f2e;
  letter-spacing: 2px;
}

.stmt-header h2 {
  margin: 4px 0 0;
  font-size: 13px;
  font-weight: normal;
  color: #555;
}

.stmt-title {
  text-align: center;
  margin: 0 0 20px;
}

.stmt-title span {
  font-size: 16px;
  font-weight: bold;
  letter-spacing: 3px;
  border: 2px solid #2c5f2e;
  padding: 4px 18px;
  color: #2c5f2e;
}

.meta-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0 40px;
  margin-bottom: 20px;
}

.meta-block h4 {
  margin: 0 0 6px;
  font-size: 11px;
  text-transform: uppercase;
  color: #888;
  border-bottom: 1px solid #ddd;
  padding-bottom: 3px;
}

.meta-block p {
  margin: 3px 0;
  font-size: 13px;
}

.meta-block .label {
  color: #666;
  font-size: 11px;
}

table.schedule {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 20px;
}

table.schedule thead th {
  background: #2c5f2e;
  color: #fff;
  padding: 8px 10px;
  text-align: left;
  font-size: 12px;
}

table.schedule tbody td {
  padding: 8px 10px;
  border-bottom: 1px solid #eee;
  font-size: 13px;
}

table.schedule tbody tr:last-child td {
  border-bottom: none;
}

table.schedule tfoot td {
  padding: 8px 10px;
  font-weight: bold;
  border-top: 2px solid #2c5f2e;
  background: #f0f7f0;
}

.badge {
  display: inline-block;
  padding: 2px 10px;
  border-radius: 10px;
  font-size: 11px;
  font-weight: bold;
}

.badge-paid     { background: #d4edda; color: #155724; }
.badge-pending  { background: #e2e3e5; color: #383d41; }
.badge-overdue  { background: #f8d7da; color: #721c24; }

.summary-wrap {
  display: flex;
  justify-content: flex-end;
  margin-bottom: 20px;
}

.summary-table {
  width: 340px;
  border-collapse: collapse;
}

.summary-table td {
  padding: 6px 10px;
  font-size: 13px;
  border-bottom: 1px solid #eee;
}

.summary-table .total-row {
  font-weight: bold;
  font-size: 14px;
  background: #f0f7f0;
  border-top: 2px solid #2c5f2e;
}

.summary-table .outstanding-row {
  font-weight: bold;
  font-size: 16px;
  background: #fff3cd;
  border-top: 2px solid #c0392b;
  color: #c0392b;
}

.summary-table .govt-row {
  font-size: 12px;
  color: #555;
}

.contract-status {
  display: inline-block;
  padding: 3px 14px;
  border-radius: 12px;
  font-size: 12px;
  font-weight: bold;
}

.status-ongoing     { background: #cce5ff; color: #004085; }
.status-completed  { background: #d4edda; color: #155724; }
.status-terminated { background: #f8d7da; color: #721c24; }
.status-draft      { background: #e2e3e5; color: #383d41; }

.footer {
  border-top: 1px solid #ddd;
  padding-top: 10px;
  margin-top: 20px;
  font-size: 11px;
  color: #888;
  text-align: center;
}
